protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Breaking change: discriminator property renamed from "Discriminator" to "$type".
    // Preserve old name so existing documents remain queryable.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Breaking change: id property no longer contains discriminator prefix.
    // Preserve old "Blog|1" format so existing documents remain accessible.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // Breaking change: HasIndex now throws for Cosmos DB entities.
    // Cosmos indexing is managed via the container's indexing policy, not EF Core.
    // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
}

